code:
with cte_outer as (
 select 1
)
select * from (
 with cte_inner as (
 select * from (
 with cte_inner_inner as (
 select * from cte_outer
 )
 select * from cte_inner_inner
 )
 )
 select * from cte_inner
)

select * from (
 select earnings, year, s
 from coursesales
 join yearswithcomplextypes on year = y
)
pivot (
 sum(earnings)
 for s in ((1, 'a'), (2, 'b'))
)

select transform(a)
using 'cat' as (a)
from t

from(
 from script_trans
 select transform(a, b)
 using 'cat' as (`a` int, b string)
) t
select a + 1

from(
 select transform(a, sum(b))
 using 'cat' as (`a` int, b string)
 from script_trans
 group by a
) t
select (b + 1) as result
order by result

from (select 1 as key, 100 as value) src
map src.*, src.key, cast(src.key / 10 as int), cast(src.key % 10 as int), src.value
 using 'cat' as (k, v, tkey, ten, one, tvalue)

from (
 select transform(a, b)
 using 'cat' as (a, b)
 from complex_trans
 cluster by a
) map_output
select transform(a, b)
 using 'cat' as (a, b)

from (
 select transform(a, b)
 using 'cat' as (a, b)
 from complex_trans
 order by a
) map_output
select transform(a, b)
 using 'cat' as (a, b)

select transform (a, b)
 using 'cat' as (a char(10), b varchar(10))
from values('apache', 'spark') t(a, b)

select (col1 || col2) col
from (
 select
 encode(string(id), 'utf-8') col1,
 encode(string(id + 1), 'utf-8') col2
 from range(10)
)

select (col1 || col2 || col3 || col4) col
from (
 select
 encode(string(id), 'utf-8') col1,
 encode(string(id + 1), 'utf-8') col2,
 encode(string(id + 2), 'utf-8') col3,
 encode(string(id + 3), 'utf-8') col4
 from range(10)
)

select ((col1 || col2) || (col3 || col4)) col
from (
 select
 encode(string(id), 'utf-8') col1,
 encode(string(id + 1), 'utf-8') col2,
 encode(string(id + 2), 'utf-8') col3,
 encode(string(id + 3), 'utf-8') col4
 from range(10)
)

select elt(2, col1, col2) col
from (
 select
 encode(string(id), 'utf-8') col1,
 encode(string(id + 1), 'utf-8') col2
 from range(10)
)

select udf(f1), udf(unique2), case when udf(udf(unique2)) is null then udf(f1) else 0 end
 from int4_tbl a left join tenk1 b on udf(f1) = udf(udf(unique2))
 where (case when udf(unique2) is null then udf(f1) else 0 end) = 0

select * from (
 select earnings, year, s
 from coursesales
 join yearswithcomplextypes on year = y
)
pivot (
 udf(sum(earnings))
 for s in ((1, 'a'), (2, 'b'))
